using System; using System.Collections.Generic;
class Program {
  static List<string> Justify(List<string> words, int maxWidth) { var res = new List<string>(); int i = 0; while (i < words.Count) { int j = i, total = 0; while (j < words.Count && total + words[j].Length + (j - i) <= maxWidth) { total += words[j].Length; j++; } int gaps = j - i - 1; string line; if (j == words.Count || gaps == 0) { line = string.Join(" ", words.GetRange(i, j - i)); line += new string(' ', maxWidth - line.Length); } else { int spaces = maxWidth - total, baseSpaces = spaces / gaps, extra = spaces % gaps; var sb = new System.Text.StringBuilder(); for (int k = i; k < j - 1; k++) { sb.Append(words[k]); sb.Append(new string(' ', baseSpaces + ((k - i < extra) ? 1 : 0))); } sb.Append(words[j - 1]); line = sb.ToString(); } res.Add(line); i = j; } return res; }
  static void Main() { var lines = Console.In.ReadToEnd().Split(new[] { "\r\n", "\n" }, StringSplitOptions.None); if (lines.Length == 0 || lines[0] == "") return; int idx = 0, t = int.Parse(lines[idx++]); var outp = new List<string>(); for (int tc = 0; tc < t; tc++) { int n = int.Parse(lines[idx++]); var words = new List<string>(); for (int i = 0; i < n; i++) words.Add(lines[idx++]); int width = int.Parse(lines[idx++]); var ans = Justify(words, width); outp.Add(ans.Count.ToString()); foreach (var s in ans) outp.Add("|" + s + "|"); if (tc + 1 < t) outp.Add("="); } Console.Write(string.Join("\n", outp)); }
}
